+#[test]
+fn subsystem_serde_roundtrip() {
+    for sub in [
+        Subsystem::Compiler,
+        Subsystem::Runtime,
+        Subsystem::ControlPlane,
+        Subsystem::ExtensionHost,
+        Subsystem::EvidencePipeline,
+    ] {
+        let json = serde_json::to_string(&sub).unwrap();
+        let back: Subsystem = serde_json::from_str(&json).unwrap();
+        assert_eq!(back, sub);
+    }
+}
