+        LossDimension::EvidenceIntegrityCost.to_string(),
+        "evidence_integrity_cost"
+    );
+}
+
+#[test]
+fn loss_dimension_serde_roundtrip() {
+    for dim in [
+        LossDimension::UserHarm,
+        LossDimension::PerformanceCost,
+        LossDimension::FalsePositiveCost,
