+            active_conditions: vec![],
+        }],
+        all_defender_actions: all,
+    };
+    let admissible = automaton.admissible_actions();
+    assert_eq!(admissible.len(), 2);
+    assert!(admissible.contains(&aid("d1")));
+    assert!(admissible.contains(&aid("d3")));
