+#[test]
+fn quote_is_fresh_at_boundary() {
+    let tr = root("k1", 42);
+    let m = meas(&tr);
+    let mut q = tr.attest(&m, [0u8; 32], 100);
+    q.issued_at_ns = 1000;
+    // Exactly at boundary: issued_at + validity = 1100
+    assert!(q.is_fresh_at(1100));
+    assert!(!q.is_fresh_at(1101));
+}
