+    let m = meas(&tr);
+    let mut q = tr.attest(&m, [0u8; 32], 100);
+    q.issued_at_ns = 1000;
+    for ts in [999, 1000, 1050, 1100, 1101, 2000] {
+        assert_eq!(q.is_expired_at(ts), !q.is_fresh_at(ts));
+    }
+}
