+    let tr = root("k1", 10);
+    let m = meas(&tr);
+    let nonce = [1u8; 32];
+    let q = fresh_quote(&tr, &m, nonce);
+    let other = tr.measure(b"other-code", b"cfg", b"pol", b"sch", "2.0");
+    let result = tr.verify(&q, &other, &nonce, 500);
+    assert!(matches!(
+        result,
