+    let mut tr = root("k1", 10);
+    let m = meas(&tr);
+    let nonce = [1u8; 32];
+    let q = fresh_quote(&tr, &m, nonce);
+    tr.revoke_key("k1");
+    let result = tr.verify(&q, &m, &nonce, 500);
+    assert!(matches!(result, VerificationResult::SignerRevoked { .. }));
