+            rhs: 1,
+        }, // 6: r4 = limit - counter
+        Ir3Instruction::JumpIf { cond: 4, target: 4 }, // 7: if r4 truthy, loop
+        Ir3Instruction::Halt,                          // 8
+    ]);
+    assert_eq!(qjs_run(&m).unwrap().value, Value::Int(15));
