+                merge_op: MergeOperator::Precedence,
+                property_claims: claims.clone(),
+                constraints: Vec::new(),
+                decision_point: None,
+                priority: 1,
+            },
+            PolicyIrNode {
+                node_id: "node-y".to_string(),
+                grants: vec![AuthorityGrant {
+                    subject: "user-y".to_string(),
+                    capability: cap,
+                    conditions: BTreeSet::new(),
