+        .expect("q2");
+    let k1: Vec<&str> = first.iter().map(|r| r.key.as_str()).collect();
+    let k2: Vec<&str> = second.iter().map(|r| r.key.as_str()).collect();
+    assert_eq!(k1, k2);
